package com.apitable.workspace.enums;

/**
 * <p>
 * view type
 * </p>
 *
 * @author Benson Cheung
 */
public enum ViewType {

    NOT_SUPPORT(0),
    //и°®ж†ЉиІЖеЫЊ
    GRID(1),
    //зЬЛжЭњиІЖеЫЊ
    KANBAN(2),
    //зЫЄеЖМиІЖеЫЊ
    GALLERY(3),

    FORM(4),
    //жЧ•еОЖиІЖеЫЊ
    CALENDAR(5),
    //зФШзЙєиІЖеЫЊ
    GANTT(6),
    //жЮґжЮДиІЖеЫЊ
    ARCHITECTURE(7),
    //е±ВзЇІиІЖеЫЊ
    HIERARCHY(8)
    ;

    private int type;

    ViewType(int type) {
        this.type = type;
    }

    public int getType() {
        return type;
    }

    public void setType(int type) {
        this.type = type;
    }
}

