  1вЖТpackage com.apitable.statistics.service.impl;
  2вЖТ
  3вЖТimport cn.hutool.core.date.DatePattern;
  4вЖТimport cn.hutool.core.date.DateUtil;
  5вЖТimport cn.hutool.json.JSONArray;
  6вЖТimport cn.hutool.json.JSONUtil;
  7вЖТimport com.apitable.statistics.dto.*;
  8вЖТimport com.apitable.statistics.entity.DataStatisticsEntity;
  9вЖТimport com.apitable.statistics.mapper.DataStatisticsMapper;
 10вЖТimport com.apitable.statistics.service.IDataStatisticsService;
 11вЖТimport com.apitable.statistics.vo.DataStatisticsVo;
 12вЖТimport com.apitable.workspace.enums.NodeType;
 13вЖТimport com.baomidou.mybatisplus.core.conditions.Wrapper;
 14вЖТimport com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
 15вЖТimport com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
 16вЖТimport com.luckysheet.common.constant.LuckConstant;
 17вЖТimport lombok.extern.slf4j.Slf4j;
 18вЖТimport org.apache.commons.collections4.CollectionUtils;
 19вЖТimport org.springframework.data.redis.core.RedisTemplate;
 20вЖТimport org.springframework.stereotype.Service;
 21вЖТ
 22вЖТimport jakarta.annotation.Resource;
 23вЖТimport java.math.BigDecimal;
 24вЖТimport java.text.NumberFormat;
 25вЖТimport java.time.LocalDate;
 26вЖТimport java.util.ArrayList;
 27вЖТimport java.util.List;
 28вЖТimport java.util.Map;
 29вЖТimport java.util.concurrent.TimeUnit;
 30вЖТimport java.util.stream.Collectors;
 31вЖТ
 32вЖТ@Service
 33вЖТ@Slf4j
 34вЖТpublic class DataStatisticsServiceImpl extends ServiceImpl<DataStatisticsMapper, DataStatisticsEntity> implements IDataStatisticsService {
 35вЖТ
 36вЖТ    @Resource
 37вЖТ    private DataStatisticsMapper dataStatisticsMapper;
 38вЖТ    @Resource
 39вЖТ    private RedisTemplate<String,Object> redisTemplate;
 40вЖТ    @Override
 41вЖТ    public void dailyStatistics() {
 42вЖТ        Long spaceNum = dataStatisticsMapper.querySpaceNum();
 43вЖТ        Long spaceMemberCountOverTen = dataStatisticsMapper.querySpaceMemberCountOverTen();
 44вЖТ
 45вЖТ        //жАїжИРеСШдЇЇжХ∞top 10зЪДз©ЇйЧізЂЩ
 46вЖТ        List<SpaceRankDto> spaceMemberCountRankData = dataStatisticsMapper.querySpaceMemberCountRankData();
 47вЖТ
 48вЖТ        Long registeredUserNum = dataStatisticsMapper.queryRegisteredUserNum();
 49вЖТ
 50вЖТ
 51вЖТ        List<FormTypeCountDto> formTypeCountDtos = dataStatisticsMapper.queryDataSheetTypeCount();
 52вЖТ        Map<Integer, Long> formTypeCountMap = formTypeCountDtos.stream().collect(Collectors.toMap(FormTypeCountDto::getFormType, FormTypeCountDto::getFormCount));
 53вЖТ        Long smartFormNum = formTypeCountMap.get(NodeType.DATASHEET.getNodeType());
 54вЖТ        Long magicFormNum = formTypeCountMap.get(NodeType.FORM.getNodeType());
 55вЖТ        Long dashboardNum = formTypeCountMap.get(NodeType.DASHBOARD.getNodeType());
 56вЖТ        Long mirrorNum = formTypeCountMap.get(NodeType.MIRROR.getNodeType());
 57вЖТ
 58вЖТ        // еИЫеїЇжЩЇиГљи°®ж†ЉжХ∞еЙН5зЪДз©ЇйЧіпЉИињЩйЗМйЩ§дЇЖdatasheetињШеМЕжЛђform,dashboard,mirrorпЉЙ
 59вЖТ        List<SpaceRankDto> spaceFormCountRankData = dataStatisticsMapper.querySpaceFormCountRankData();
 60вЖТ
 61вЖТ        //ињЩйЗМеП™жШѓdatasheetзЪДжХ∞зЫЃпЉМеРОйЭҐзЃЧеє≥еЭЗжХ∞зФ®
 62вЖТ        Long spaceDataSheetNum = dataStatisticsMapper.querySpaceDataSheetNum();
