import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;

import jakarta.annotation.Resource;
import java.math.BigDecimal;
import java.text.NumberFormat;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.concurrent.TimeUnit;
import java.util.stream.Collectors;

@Service
@Slf4j
public class DataStatisticsServiceImpl extends ServiceImpl<DataStatisticsMapper, DataStatisticsEntity> implements IDataStatisticsService {

    @Resource
    private DataStatisticsMapper dataStatisticsMapper;
    @Resource
    private RedisTemplate<String,Object> redisTemplate;
    @Override
    public void dailyStatistics() {
        Long spaceNum = dataStatisticsMapper.querySpaceNum();
        Long spaceMemberCountOverTen = dataStatisticsMapper.querySpaceMemberCountOverTen();

        //жАїжИРеСШдЇЇжХ∞top 10зЪДз©ЇйЧізЂЩ
        List<SpaceRankDto> spaceMemberCountRankData = dataStatisticsMapper.querySpaceMemberCountRankData();

        Long registeredUserNum = dataStatisticsMapper.queryRegisteredUserNum();


        List<FormTypeCountDto> formTypeCountDtos = dataStatisticsMapper.queryDataSheetTypeCount();
        Map<Integer, Long> formTypeCountMap = formTypeCountDtos.stream().collect(Collectors.toMap(FormTypeCountDto::getFormType, FormTypeCountDto::getFormCount));
        Long smartFormNum = formTypeCountMap.get(NodeType.DATASHEET.getNodeType());
        Long magicFormNum = formTypeCountMap.get(NodeType.FORM.getNodeType());
        Long dashboardNum = formTypeCountMap.get(NodeType.DASHBOARD.getNodeType());
        Long mirrorNum = formTypeCountMap.get(NodeType.MIRROR.getNodeType());

        // еИЫеїЇжЩЇиГљи°®ж†ЉжХ∞еЙН5зЪДз©ЇйЧіпЉИињЩйЗМйЩ§дЇЖdatasheetињШеМЕжЛђform,dashboard,mirrorпЉЙ
        List<SpaceRankDto> spaceFormCountRankData = dataStatisticsMapper.querySpaceFormCountRankData();

        //ињЩйЗМеП™жШѓdatasheetзЪДжХ∞зЫЃпЉМеРОйЭҐзЃЧеє≥еЭЗжХ∞зФ®
        Long spaceDataSheetNum = dataStatisticsMapper.querySpaceDataSheetNum();
        Long maxFormRecordNum = dataStatisticsMapper.querySpaceFormMaxRecordNum();
        Long spaceFormRecordTotalNum = dataStatisticsMapper.querySpaceFormRecordTotalNum();
        BigDecimal avgFormRecordNum = new BigDecimal(spaceFormRecordTotalNum).divide(new BigDecimal(spaceDataSheetNum), 2, BigDecimal.ROUND_HALF_UP);

        Long spaceFormMaxVersion = dataStatisticsMapper.querySpaceFormMaxVersion();
        BigDecimal spaceFormAvgVersion = dataStatisticsMapper.querySpaceFormAvgVersion();

        //luckysheet
        Long luckyNum = dataStatisticsMapper.queryLuckyNum();
        //luckysheet еИЫеїЇи°®ж†ЉжХ∞еЙН5зЪДз©ЇйЧі
        List<SpaceRankDto> spaceLuckySheetCountRankData = dataStatisticsMapper.querySpaceLuckySheetCountRankData();

        Long maxLuckySheetNum = dataStatisticsMapper.queryMaxLuckySheetNum();
        BigDecimal avgLuckySheetNum = dataStatisticsMapper.queryAvgLuckySheetNum();

        // dstеТМжѓПдЄ™и°®ж†ЉйЗМзЪДиІЖеЫЊ
        List<FormViewTypesDto> formViewTypesDtos = dataStatisticsMapper.querySpaceFormView();
        Long gridViewNum = 0L;
        Long kanbanViewNum = 0L;
        Long galleryViewNum = 0L;
        Long calendarViewNum = 0L;
        Long ganttViewNum = 0L;
        Long architectureViewNum = 0L;
        Long hierarchyViewNum = 0L;
        Long maxFormViewNum = 0L;
        for (FormViewTypesDto formViewTypesDto : formViewTypesDtos) {
            JSONArray viewTypeArray = JSONUtil.parseArray(formViewTypesDto.getViewTypes());
            int formViewNum = viewTypeArray.size();
            maxFormViewNum = Math.max(maxFormViewNum, formViewNum);
            for (Object viewType : viewTypeArray) {
                String type = viewType.toString();
                switch (type) {
                    case "1":
                        gridViewNum++;
                        break;
                    case "2":
                        kanbanViewNum++;
                        break;
                    case "3":
                        galleryViewNum++;
                        break;
                    case "5":
                        calendarViewNum++;
                        break;
                    case "6":
                        ganttViewNum++;
                        break;
                    case "7":
                        architectureViewNum++;
                        break;
                    case "8":
                        hierarchyViewNum++;
                        break;
                    default:
                        break;
                }
            }
        }
        Long totalViewNum = gridViewNum + kanbanViewNum + galleryViewNum + calendarViewNum + ganttViewNum + architectureViewNum + hierarchyViewNum;
        BigDecimal avgFormViewNum = new BigDecimal(totalViewNum).divide(new BigDecimal(spaceDataSheetNum), 2, BigDecimal.ROUND_HALF_UP);

        String statisticsDay = DateUtil.format(DateUtil.date(), DatePattern.NORM_DATE_PATTERN);

        Object exceptionCount = redisTemplate.opsForValue().get(LuckConstant.getLuckExceptionCountKey());

        Long todayExcelExceptionCount = exceptionCount == null ? 0L : Long.parseLong(exceptionCount.toString());
        Long todayExcelUserCount = redisTemplate.opsForSet().size(LuckConstant.getLuckExcelUserSetKey());
        redisTemplate.expire(LuckConstant.getLuckExceptionCountKey(), 7, TimeUnit.DAYS);
        redisTemplate.expire(LuckConstant.getLuckExcelUserSetKey(), 7, TimeUnit.DAYS);

        Long todayExcelAddCount = dataStatisticsMapper.queryNewAddLuckySheetNum();
        Long todayExcelUpdateCount = dataStatisticsMapper.queryNewUpdateLuckySheetNum();
        Long todayMsgUserReadNum = dataStatisticsMapper.queryDayNewUpdateMsgUserNum();
        Long todayMsgUserNum = dataStatisticsMapper.queryDayNewAddMsgUserNum();
        Long todayMsgNum = dataStatisticsMapper.queryDayNewAddMsgNum();
        Long todayMsgReadNum = dataStatisticsMapper.queryDayNewUpdateMsgNum();

        // жЬЇеЩ®дЇЇињРи°МжХ∞жНЃ
        List<RobotCountDto> robotCountDtos = dataStatisticsMapper.queryRobotCountData(LocalDate.now());
        List<TriggerTypeRunCountDto> triggerTypeRunCountDtos = dataStatisticsMapper.queryTriggerTypeRunCounts(LocalDate.now());

        Long robotAllTypeActive = 0L;
        Long robotAllTypeInactive = 0L;
        Long robotFormSubmittedActive = 0L;
        Long robotFormSubmittedInactive = 0L;
        Long robotRecordMatchesConditionsActive = 0L;
        Long robotRecordMatchesConditionsInactive = 0L;
        Long robotRecordCreatedActive = 0L;
        Long robotRecordCreatedInactive = 0L;
        Long robotRegularTimeActive = 0L;
        Long robotRegularTimeInactive = 0L;
        Long robotRecordMatchesChangeActive = 0L;
        Long robotRecordMatchesChangeInactive = 0L;

        for (RobotCountDto dto : robotCountDtos) {
            switch (dto.getTriggerTypeName()) {
                case "All": // ж≥®жДПпЉЪз°ЃдњЭжЯ•иѓҐеЫЮзЪДжХ∞жНЃдЄОињЩйЗМеМєйЕНпЉМињЩйЗМеБЗиЃЊиІ¶еПСеЩ®з±їеЮЛеРНдЄЇвАЬallвАЭдєЯеМєйЕН
                    robotAllTypeActive = dto.getActiveRobots();
                    robotAllTypeInactive = dto.getInactiveRobots();
                    break;
                case "form_submitted":
                    robotFormSubmittedActive = dto.getActiveRobots();
                    robotFormSubmittedInactive = dto.getInactiveRobots();
                    break;
                case "record_matches_conditions":
                    robotRecordMatchesConditionsActive = dto.getActiveRobots();
                    robotRecordMatchesConditionsInactive = dto.getInactiveRobots();
                    break;
                case "record_created":
                    robotRecordCreatedActive = dto.getActiveRobots();
                    robotRecordCreatedInactive = dto.getInactiveRobots();
                    break;
                case "regular_time":
                    robotRegularTimeActive = dto.getActiveRobots();
                    robotRegularTimeInactive = dto.getInactiveRobots();
                    break;
                case "record_matches_change":
                    robotRecordMatchesChangeActive = dto.getActiveRobots();
                    robotRecordMatchesChangeInactive = dto.getInactiveRobots();
                    break;
                default:
                    break;
            }
        }

        Long robotFormSubmittedRunCount = 0L;
        Long robotRecordMatchesConditionsRunCount = 0L;
        Long robotRecordCreatedRunCount = 0L;
        Long robotRegularTimeRunCount = 0L;
        Long robotRecordMatchesChangeRunCount = 0L;
        Long robotAllRunCount = 0L;

        for (TriggerTypeRunCountDto dto : triggerTypeRunCountDtos) {
            switch (dto.getTriggerTypeName()) {
                case "form_submitted":
                    robotFormSubmittedRunCount = dto.getRunCount();
                    break;
                case "record_matches_conditions":
                    robotRecordMatchesConditionsRunCount = dto.getRunCount();
                    break;
                case "record_created":
                    robotRecordCreatedRunCount = dto.getRunCount();
                    break;
                case "regular_time":
                    robotRegularTimeRunCount = dto.getRunCount();
                    break;
                case "record_matches_change":
                    robotRecordMatchesChangeRunCount = dto.getRunCount();
                    break;
                case "all":
                    robotAllRunCount = dto.getRunCount();
                    break;
                default:
                    // е§ДзРЖйїШиЃ§жГЕеЖµжИЦиЃ∞ељХжЧ•ењЧ
                    break;
            }
        }


        DataStatisticsEntity dataStatisticsEntity = DataStatisticsEntity.builder()
                .spaceNum(spaceNum)
                .spaceMemberCountOverTen(spaceMemberCountOverTen)
                .spaceMemberCountRankData(JSONUtil.toJsonStr(spaceMemberCountRankData))
                .registeredUserNum(registeredUserNum)
                .smartFormNum(smartFormNum)
                .magicFormNum(magicFormNum)
                .dashboardNum(dashboardNum)
                .mirrorNum(mirrorNum)
                .spaceFormCountRankData(JSONUtil.toJsonStr(spaceFormCountRankData))
                .maxFormRecordNum(maxFormRecordNum)
                .avgFormRecordNum(avgFormRecordNum)
                .maxFormVersionNum(spaceFormMaxVersion)
                .avgFormVersionNum(spaceFormAvgVersion)
                .luckyNum(luckyNum)
                .maxLuckySheetNum(maxLuckySheetNum)
                .avgLuckySheetNum(avgLuckySheetNum)
                .spaceLuckySheetCountRankData(JSONUtil.toJsonStr(spaceLuckySheetCountRankData))
                .gridViewNum(gridViewNum)
                .kanbanViewNum(kanbanViewNum)
                .galleryViewNum(galleryViewNum)
                .calendarViewNum(calendarViewNum)
                .ganttViewNum(ganttViewNum)
                .architectureViewNum(architectureViewNum)
                .hierarchyViewNum(hierarchyViewNum)
                .maxFormViewNum(maxFormViewNum)
                .avgFormViewNum(avgFormViewNum)
                .statisticsDay(statisticsDay)
                .luckyTodayAddCount(todayExcelAddCount)
                .luckyTodayUpdateCount(todayExcelUpdateCount)
                .luckyTodayUserCount(todayExcelUserCount)
                .luckyTodayExceptionCount(todayExcelExceptionCount)
                .todayMsgNum(todayMsgNum)
                .todayMsgReadNum(todayMsgReadNum)
                .todayMsgUserNum(todayMsgUserNum)
                .todayMsgUserReadNum(todayMsgUserReadNum)
                .robotAllTypeActive(robotAllTypeActive)
                .robotAllTypeInactive(robotAllTypeInactive)
                .robotFormSubmittedActive(robotFormSubmittedActive)
                .robotFormSubmittedInactive(robotFormSubmittedInactive)
                .robotRecordMatchesConditionsActive(robotRecordMatchesConditionsActive)
                .robotRecordMatchesConditionsInactive(robotRecordMatchesConditionsInactive)
                .robotRecordCreatedActive(robotRecordCreatedActive)
                .robotRecordCreatedInactive(robotRecordCreatedInactive)
                .robotRegularTimeActive(robotRegularTimeActive)
                .robotRegularTimeInactive(robotRegularTimeInactive)
                .robotRecordMatchesChangeActive(robotRecordMatchesChangeActive)
                .robotRecordMatchesChangeInactive(robotRecordMatchesChangeInactive)
                .robotFormSubmittedRunCount(robotFormSubmittedRunCount)
                .robotRecordMatchesConditionsRunCount(robotRecordMatchesConditionsRunCount)
                .robotRecordCreatedRunCount(robotRecordCreatedRunCount)
                .robotRegularTimeRunCount(robotRegularTimeRunCount)
                .robotRecordMatchesChangeRunCount(robotRecordMatchesChangeRunCount)
                .robotAllRunCount(robotAllRunCount)
                .build();
        LambdaQueryWrapper<DataStatisticsEntity> queryWrapper = new LambdaQueryWrapper<>();
        queryWrapper.eq(DataStatisticsEntity::getStatisticsDay, statisticsDay);
        DataStatisticsEntity queryOne = dataStatisticsMapper.selectOne(queryWrapper);
        if (queryOne != null) {
            LambdaQueryWrapper<DataStatisticsEntity> updateWrapper = new LambdaQueryWrapper<>();
            updateWrapper.eq(DataStatisticsEntity::getStatisticsDay, statisticsDay);
            dataStatisticsMapper.update(dataStatisticsEntity,updateWrapper);
        } else {
            dataStatisticsMapper.insert(dataStatisticsEntity);
        }
    }

    @Override
    public DataStatisticsVo getLastStatisticsData() {
        LambdaQueryWrapper<DataStatisticsEntity> queryWrapper = new LambdaQueryWrapper<>();
        queryWrapper.orderByDesc(DataStatisticsEntity::getId);
        queryWrapper.last("limit 1");
        DataStatisticsEntity entity = getOne(queryWrapper);
        if (entity != null) {
            DataStatisticsVo dataStatisticsVo = new DataStatisticsVo();
            dataStatisticsVo.setSpaceNum(entity.getSpaceNum());
            dataStatisticsVo.setSpaceMemberCountOverTen(entity.getSpaceMemberCountOverTen());
            dataStatisticsVo.setRegisteredUserNum(entity.getRegisteredUserNum());
            dataStatisticsVo.setSmartFormNum(entity.getSmartFormNum());
            dataStatisticsVo.setDashboardNum(entity.getDashboardNum());
            dataStatisticsVo.setMirrorNum(entity.getMirrorNum());
            dataStatisticsVo.setMagicFormNum(entity.getMagicFormNum());
            dataStatisticsVo.setGridViewNum(entity.getGridViewNum());
            dataStatisticsVo.setKanbanViewNum(entity.getKanbanViewNum());
            dataStatisticsVo.setGalleryViewNum(entity.getGalleryViewNum());
            dataStatisticsVo.setCalendarViewNum(entity.getCalendarViewNum());
            dataStatisticsVo.setGanttViewNum(entity.getGanttViewNum());
            dataStatisticsVo.setArchitectureViewNum(entity.getArchitectureViewNum());
            dataStatisticsVo.setHierarchyViewNum(entity.getHierarchyViewNum());
            dataStatisticsVo.setMaxFormRecordNum(entity.getMaxFormRecordNum());
            dataStatisticsVo.setAvgFormRecordNum(entity.getAvgFormRecordNum());
            dataStatisticsVo.setMaxFormViewNum(entity.getMaxFormViewNum());
            dataStatisticsVo.setAvgFormViewNum(entity.getAvgFormViewNum());
            dataStatisticsVo.setMaxFormVersionNum(entity.getMaxFormVersionNum());
            dataStatisticsVo.setAvgFormVersionNum(entity.getAvgFormVersionNum());
            dataStatisticsVo.setLuckyNum(entity.getLuckyNum());
            dataStatisticsVo.setMaxLuckySheetNum(entity.getMaxLuckySheetNum());
            dataStatisticsVo.setAvgLuckySheetNum(entity.getAvgLuckySheetNum());
            dataStatisticsVo.setStatisticsDay(entity.getStatisticsDay());

            dataStatisticsVo.setSpaceMemberCountRankData(JSONUtil.toList(entity.getSpaceMemberCountRankData(), SpaceRankDto.class));
            dataStatisticsVo.setSpaceFormCountRankData(JSONUtil.toList(entity.getSpaceFormCountRankData(), SpaceRankDto.class));
            dataStatisticsVo.setSpaceLuckySheetCountRankData(JSONUtil.toList(entity.getSpaceLuckySheetCountRankData(), SpaceRankDto.class));
            return dataStatisticsVo;
        }
        return null;
    }

    @Override
    public List<DataStatisticsVo> getExcelStatisticsDataList() {
        LambdaQueryWrapper<DataStatisticsEntity> queryWrapper = new LambdaQueryWrapper<>();
        queryWrapper.select(
            DataStatisticsEntity::getStatisticsDay,
            DataStatisticsEntity::getLuckyNum,
            DataStatisticsEntity::getLuckyTodayAddCount,
            DataStatisticsEntity::getLuckyTodayUpdateCount,
            DataStatisticsEntity::getLuckyTodayUserCount,
            DataStatisticsEntity::getLuckyTodayExceptionCount)
        ;
        queryWrapper.orderByDesc(DataStatisticsEntity::getId);
        queryWrapper.last("limit 30");
        List<DataStatisticsEntity> statisticsList =  list(queryWrapper);
        if(CollectionUtils.isNotEmpty(statisticsList)){
            return statisticsList.stream().map(dataStatisticsEntity -> {
                DataStatisticsVo dataStatisticsVo = new DataStatisticsVo();
                dataStatisticsVo.setStatisticsDay(dataStatisticsEntity.getStatisticsDay());
                dataStatisticsVo.setLuckyNum(dataStatisticsEntity.getLuckyNum());
                dataStatisticsVo.setLuckyTodayAddCount(dataStatisticsEntity.getLuckyTodayAddCount());
                dataStatisticsVo.setLuckyTodayUpdateCount(dataStatisticsEntity.getLuckyTodayUpdateCount());
                dataStatisticsVo.setLuckyTodayUserCount(dataStatisticsEntity.getLuckyTodayUserCount());
                dataStatisticsVo.setLuckyTodayExceptionCount(dataStatisticsEntity.getLuckyTodayExceptionCount());
                return dataStatisticsVo;
            }).collect(Collectors.toList());
        }
        return new ArrayList<>();
    }

    @Override
    public List<DataStatisticsVo> getMsgStatisticsDataList() {
        LambdaQueryWrapper<DataStatisticsEntity> queryWrapper = new LambdaQueryWrapper<>();
        queryWrapper.select(
            DataStatisticsEntity::getStatisticsDay,
            DataStatisticsEntity::getTodayMsgNum,
            DataStatisticsEntity::getTodayMsgReadNum,
            DataStatisticsEntity::getTodayMsgUserNum,
            DataStatisticsEntity::getTodayMsgUserReadNum
         )
        ;
        queryWrapper.orderByDesc(DataStatisticsEntity::getId);
        queryWrapper.last("limit 30");
        List<DataStatisticsEntity> statisticsList =  list(queryWrapper);
        if(CollectionUtils.isNotEmpty(statisticsList)){
            return statisticsList.stream().map(dataStatisticsEntity -> {
                DataStatisticsVo dataStatisticsVo = new DataStatisticsVo();
                dataStatisticsVo.setStatisticsDay(dataStatisticsEntity.getStatisticsDay());
                dataStatisticsVo.setTodayMsgNum(dataStatisticsEntity.getTodayMsgNum());
                dataStatisticsVo.setTodayMsgReadNum(dataStatisticsEntity.getTodayMsgReadNum());
                dataStatisticsVo.setTodayMsgUserNum(dataStatisticsEntity.getTodayMsgUserNum());
                dataStatisticsVo.setTodayMsgUserReadNum(dataStatisticsEntity.getTodayMsgUserReadNum());
                NumberFormat numberFormat = NumberFormat.getInstance();
                // compute parsing progress
                numberFormat.setMaximumFractionDigits(2);
                String format = "0%";
                if (dataStatisticsEntity.getTodayMsgNum() != null && dataStatisticsEntity.getTodayMsgNum() != 0){
                    format = numberFormat.format(((float) (dataStatisticsEntity.getTodayMsgReadNum()) / (dataStatisticsEntity.getTodayMsgNum())) * 100).concat("%");
                }
                dataStatisticsVo.setTodayMsgReadPercent(format);
                return dataStatisticsVo;
            }).collect(Collectors.toList());
        }
        return new ArrayList<>();
    }
