file.content:
management:
  endpoints:
    web:
      exposure:
        include: health,info,prometheus
      base-path: /actuator
  endpoint:
    health:
      probes:
        enabled: true  # gives /actuator/health/liveness|readiness
  metrics:
    tags:
      application: collabspace-server
      service_name: collabspace-server
      instance: ${HOSTNAME:unknown}
server:
  port: ${SERVER_PORT:8081}
  max-http-request-header-size: ${MAX_HTTP_HEADER_SIZE:32KB}
spring:
  jackson:
    time-zone: Asia/Shanghai
  main:
    allow-circular-references: true
  application:
    name: service-api
  servlet:
    multipart:
      max-file-size: ${MAX_FILE_SIZE:1GB}
      max-request-size: ${MAX_REQUEST_SIZE:1GB}
  session:
    redis:
      namespace: ${SESSION_NAMESPACE:echo:session}
      repository-type: indexed
    timeout: ${SESSION_TIMEOUT:30d}
  datasource:
    dynamic:
      primary: master
      strict: false
      datasource:
        master:
          url: jdbc:mysql://${MYSQL_HOST:10.57.0.45}:${MYSQL_PORT:30306}/${MYSQL_DATABASE:collabspace}?characterEncoding=utf8&autoReconnect=true&useSSL=${MYSQL_SSL_ENABLED:false}
          username: ${MYSQL_USERNAME:root}
          password: ${MYSQL_PASSWORD:123456}
        slave:
          url: jdbc:mysql://${MYSQL_HOST:10.57.0.45}:${MYSQL_PORT:30306}/${MYSQL_DATABASE:collabspace}?characterEncoding=utf8&autoReconnect=true&useSSL=${MYSQL_SSL_ENABLED:false}
          username: ${MYSQL_USERNAME:root}
          password: ${MYSQL_PASSWORD:123456}

  data:
    redis:
      host: ${REDIS_HOST:127.0.0.1}
      username: ${REDIS_USERNAME:}
      password: ${REDIS_PASSWORD:apitable@com}
      port: ${REDIS_PORT:6379}
      database: ${REDIS_DB:0}
      timeout: ${REDIS_TIMEOUT:30000}
      ssl:
        enabled: ${REDIS_SSL_ENABLED:false}
  rabbitmq:
    addresses: amqp://${RABBITMQ_HOST:127.0.0.1}:${RABBITMQ_PORT:5672}
    username: ${RABBITMQ_USERNAME:apitable}
    password: ${RABBITMQ_PASSWORD:apitable@com}
    publisher-returns: true
    publisher-confirm-type: correlated
    listener:
      simple:
        acknowledge-mode: manual
        prefetch: 5
        auto-startup: ${RABBITMQ_AUTO_STARTUP:true}
        retry:
          enabled: true
          max-attempts: 5

    virtual-host: ${RABBITMQ_VHOST:/}
    dynamic: ${RABBITMQ_DYNAMIC:true}
  mail:
    host: ${MAIL_HOST:smtp.map.com}
    username: ${MAIL_USERNAME:support@map.com}
    password: ${MAIL_PASSWORD:map}
    port: ${MAIL_PORT:465}
    protocol: smtp
    properties:
      mail.debug: true
      mail.smtp.auth: true
      mail.smtp.starttls.enable: ${MAIL_STARTTLS_ENABLE:true}
      mail.smtp.starttls.required: ${MAIL_STARTTLS_REQUIRED:true}
      mail.smtp.ssl.enable: ${MAIL_SSL_ENABLE:true}
      mail.smtp.socketFactory.class: javax.net.ssl.SSLSocketFactory
  logger:
    max-history-days: ${LOGGER_MAX_HISTORY_DAYS:30}
  liquibase:
    enabled: false
    change-log: classpath:/db/changelog/db.changelog-master.xml

mq:
  enabled: ${MQ_ENABLED:true}
  governance:
    auto:
      enabled: ${MQ_GOVERNANCE_AUTO_ENABLED:true}
      lazy-queue: true
      message-ttl: 600000
      max-length: 500000
      max-length-bytes: 104857600
      dead-letter-exchange: collabspace.dlx.exchange
      dead-letter-routing-key: collabspace.dlx.key

