  1вЖТpackage com.yottastudios.ns.collabspace.workspace.controller;
  2вЖТ
  3вЖТimport com.yottastudios.ns.collabspace.core.support.ResponseData;
  4вЖТimport com.yottastudios.ns.collabspace.shared.util.ExportUtil;
  5вЖТimport com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
  6вЖТimport com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
  7вЖТimport com.yottastudios.ns.collabspace.workspace.dto.MethodCountDto;
  8вЖТimport com.yottastudios.ns.collabspace.workspace.dto.TypeCountDto;
  9вЖТimport com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeTypeEnum;
 10вЖТimport com.yottastudios.ns.collabspace.workspace.manager.query.MethodLogQueryManager;
 11вЖТimport com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeStatisticsQueryManager;
 12вЖТimport com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeCreatedByTypeVo;
 13вЖТimport com.yottastudios.ns.collabspace.workspace.vo.SpaceNodePvByTypeVo;
 14вЖТimport com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeUvByTypeVo;
 15вЖТimport io.swagger.v3.oas.annotations.Operation;
 16вЖТimport io.swagger.v3.oas.annotations.tags.Tag;
 17вЖТimport jakarta.annotation.Resource;
 18вЖТimport org.springframework.format.annotation.DateTimeFormat;
 19вЖТimport org.springframework.web.bind.annotation.RequestParam;
 20вЖТimport org.springframework.web.bind.annotation.RestController;
 21вЖТ
 22вЖТimport java.io.IOException;
 23вЖТimport java.nio.charset.Charset;
 24вЖТimport java.time.LocalDateTime;
 25вЖТimport java.util.HashMap;
 26вЖТimport java.util.List;
 27вЖТimport java.util.Map;
 28вЖТ
 29вЖТ@RestController
 30вЖТ@Tag(name = "SpaceNodeStatistics")
 31вЖТ@ApiResource(path = "/node/statistics")
 32вЖТpublic class SpaceNodeStatisticsController {
 33вЖТ
 34вЖТ    @Resource
 35вЖТ    private SpaceNodeStatisticsQueryManager statisticsQueryManager;
 36вЖТ    @Resource
 37вЖТ    private MethodLogQueryManager methodLogQueryManager;
 38вЖТ
 39вЖТ    @GetResource(path = "/uv/total", requiredPermission = false, requiredLogin = false)
 40вЖТ    @Operation(summary = "зїЯиЃ°еМЇйЧіеЖЕдїїжДПжЦЗж°£зЪДеОїйЗНиЃњйЧЃзФ®жИЈжХ∞")
 41вЖТ    public ResponseData<Long> getDistinctVisitorCount(
 42вЖТ            @RequestParam("startAt") @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime startAt,
 43вЖТ            @RequestParam("endAt") @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime endAt
 44вЖТ    ) {
 45вЖТ        Long count = statisticsQueryManager.countDistinctVisitors(startAt, endAt);
 46вЖТ        return ResponseData.success(count);
 47вЖТ    }
 48вЖТ
 49вЖТ    @GetResource(path = "/uv/byType", requiredPermission = false, requiredLogin = false)
 50вЖТ    @Operation(summary = "зїЯиЃ°еМЇйЧіеЖЕеРДз±їеЮЛжЦЗж°£зЪДеОїйЗНиЃњйЧЃзФ®жИЈжХ∞")
 51вЖТ    public ResponseData<List<SpaceNodeUvByTypeVo>> getDistinctVisitorCountByType(
 52вЖТ            @RequestParam("startAt") @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime startAt,
 53вЖТ            @RequestParam("endAt") @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime endAt
 54вЖТ    ) {
 55вЖТ        return ResponseData.success(SpaceNodeUvByTypeVo.fromTypeCountDtoList(
 56вЖТ                statisticsQueryManager.countDistinctVisitorsByType(startAt, endAt)
 57вЖТ        ));
 58вЖТ    }
 59вЖТ
 60вЖТ    @GetResource(path = "/pv/byType", requiredPermission = false, requiredLogin = false)
 61вЖТ    @Operation(summary = "зїЯиЃ°еМЇйЧіеЖЕеРДз±їеЮЛжЦЗж°£зЪДиЃњйЧЃдЇЇжђ°пЉИдЄНеОїйЗНпЉЙ")
 62вЖТ    public ResponseData<List<SpaceNodePvByTypeVo>> getVisitCountByType(
 63вЖТ            @RequestParam("startAt") @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime startAt,
 64вЖТ            @RequestParam("endAt") @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime endAt
 65вЖТ    ) {
 66вЖТ        return ResponseData.success(SpaceNodePvByTypeVo.fromTypeCountDtoList(
 67вЖТ                statisticsQueryManager.countTotalVisitsByType(startAt, endAt)
 68вЖТ        ));
 69вЖТ    }
 70вЖТ
 71вЖТ    @GetResource(path = "/created/byType", requiredPermission = false, requiredLogin = false)
 72вЖТ    @Operation(summary = "зїЯиЃ°еМЇйЧіеЖЕеРДз±їеЮЛжЦЗж°£зЪДжЦ∞еїЇжХ∞йЗП")
 73вЖТ    public ResponseData<List<SpaceNodeCreatedByTypeVo>> getCreatedCountByType(
 74вЖТ            @RequestParam("startAt") @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime startAt,
 75вЖТ            @RequestParam("endAt") @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime endAt
 76вЖТ    ) {
 77вЖТ        return ResponseData.success(SpaceNodeCreatedByTypeVo.fromTypeCountDtoList(
 78вЖТ                statisticsQueryManager.countCreatedNodesByType(startAt, endAt)
 79вЖТ        ));
 80вЖТ    }
 81вЖТ
 82вЖТ    @GetResource(path = "/method/count", requiredPermission = false, requiredLogin = false)
 83вЖТ    @Operation(summary = "зїЯиЃ°еМЇйЧіеЖЕеРДжЦєж≥ХзЪДи∞ГзФ®жђ°жХ∞")
 84вЖТ    public ResponseData<List<MethodCountDto>> getMethodCallCount(
 85вЖТ            @RequestParam("startAt") @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime startAt,
 86вЖТ            @RequestParam("endAt") @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime endAt
 87вЖТ    ) {
 88вЖТ        return ResponseData.success(methodLogQueryManager.countByMethodName(startAt, endAt));
 89вЖТ    }
 90вЖТ
 91вЖТ    @GetResource(path = "/export/csv", requiredPermission = false, requiredLogin = false)
 92вЖТ    @Operation(summary = "еѓЉеЗЇзїЯиЃ°ж±ЗжАїCSV")
 93вЖТ    public void exportStatisticsCsv(
 94вЖТ            @RequestParam(value = "startAt", required = false) @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime startAt,
 95вЖТ            @RequestParam(value = "endAt", required = false) @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime endAt
 96вЖТ    ) throws IOException {
 97вЖТ        LocalDateTime resolvedEnd = endAt == null ? LocalDateTime.now() : endAt;
 98вЖТ        LocalDateTime resolvedStart = startAt == null ? resolvedEnd.minusDays(7) : startAt;
 99вЖТ
100вЖТ        Long totalUv = statisticsQueryManager.countDistinctVisitors(resolvedStart, resolvedEnd);
101вЖТ
102вЖТ        List<TypeCountDto> createdList = statisticsQueryManager.countCreatedNodesByType(resolvedStart, resolvedEnd);
103вЖТ        List<TypeCountDto> uvList = statisticsQueryManager.countDistinctVisitorsByType(resolvedStart, resolvedEnd);
104вЖТ        List<TypeCountDto> pvList = statisticsQueryManager.countTotalVisitsByType(resolvedStart, resolvedEnd);
105вЖТ
106вЖТ        Map<Integer, Long> createdMap = toCountMap(createdList);
107вЖТ        Map<Integer, Long> uvMap = toCountMap(uvList);
108вЖТ        Map<Integer, Long> pvMap = toCountMap(pvList);
109вЖТ
110вЖТ        List<SpaceNodeTypeEnum> orderedTypes = List.of(
111вЖТ                SpaceNodeTypeEnum.DATASHEET,
112вЖТ                SpaceNodeTypeEnum.FORM,
113вЖТ                SpaceNodeTypeEnum.DASHBOARD,
114вЖТ                SpaceNodeTypeEnum.MIRROR,
115вЖТ                SpaceNodeTypeEnum.AFFINE,
116вЖТ                SpaceNodeTypeEnum.OUTLINE,
117вЖТ                SpaceNodeTypeEnum.ONLYOFFICE_EXCEL,
118вЖТ                SpaceNodeTypeEnum.ONLYOFFICE_WORD,
119вЖТ                SpaceNodeTypeEnum.ONLYOFFICE_PPT,
120вЖТ                SpaceNodeTypeEnum.LINK
121вЖТ        );
122вЖТ
123вЖТ        StringBuilder sb = new StringBuilder();
124вЖТ        sb.append("жАїдљњзФ®дЇЇжХ∞,").append(totalUv == null ? 0 : totalUv).append('\n');
125вЖТ        sb.append('\n');
126вЖТ        sb.append(",жЦ∞еїЇжХ∞йЗП,иЃњйЧЃдЇЇжХ∞,иЃњйЧЃдЇЇжђ°").append('\n');
127вЖТ
128вЖТ        for (SpaceNodeTypeEnum type : orderedTypes) {
129вЖТ            String label = type.getDescription();
130вЖТ            long created = createdMap.getOrDefault(type.getValue(), 0L);
131вЖТ            long uv = uvMap.getOrDefault(type.getValue(), 0L);
132вЖТ            long pv = pvMap.getOrDefault(type.getValue(), 0L);
133вЖТ            sb.append(label).append(',')
134вЖТ                    .append(created).append(',')
135вЖТ                    .append(uv).append(',')
136вЖТ                    .append(pv).append('\n');
137вЖТ        }
138вЖТ
139вЖТ        ExportUtil.exportBytes(sb.toString().getBytes(Charset.forName("GBK")),
140вЖТ                "node_statistics.csv",
141вЖТ                "text/csv;charset=GBK");
142вЖТ    }
143вЖТ
144вЖТ    private Map<Integer, Long> toCountMap(List<TypeCountDto> list) {
145вЖТ        Map<Integer, Long> map = new HashMap<>();
146вЖТ        if (list == null) return map;
147вЖТ        for (TypeCountDto dto : list) {
148вЖТ            if (dto == null) continue;
149вЖТ            map.put(dto.getSpaceNodeType(), dto.getCount());
150вЖТ        }
151вЖТ        return map;
152вЖТ    }
153вЖТ}

