package com.apitable.statistics.controller;

import com.apitable.core.support.ResponseData;
import com.apitable.shared.component.scanner.annotation.ApiResource;
import com.apitable.shared.component.scanner.annotation.GetResource;
import com.apitable.statistics.service.IDataStatisticsService;
import com.apitable.statistics.vo.DataStatisticsVo;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.RestController;

import jakarta.annotation.Resource;
import java.util.List;

@Tag(name = "statistics data get api")
@RestController
@ApiResource(path = "/statistics")
@Slf4j
public class DataStatisticsController {

    @Resource
    private IDataStatisticsService dataStatisticsService;
    @GetResource(path = "/get",requiredLogin = false)
    @Operation(summary = "get statistics data ", description = "get statistics data")
    public ResponseData<DataStatisticsVo> getStatisticsData() {
        DataStatisticsVo lastStatisticsData = dataStatisticsService.getLastStatisticsData();
        return ResponseData.success(lastStatisticsData);
    }

    @GetResource(path = "/lucky/data/get",requiredLogin = false)
    @Operation(summary = "get lucky statistics data ", description = "get lucky statistics data")
    public ResponseData<List<DataStatisticsVo>> getLuckStatisticsData() {
        List<DataStatisticsVo> excelStatisticsDataList = dataStatisticsService.getExcelStatisticsDataList();
        return ResponseData.success(excelStatisticsDataList);
    }

    @GetResource(path = "/msg/data/get",requiredLogin = false)
    @Operation(summary = "get lucky statistics data ", description = "get lucky statistics data")
    public ResponseData<List<DataStatisticsVo>> getMsgStatisticsData() {
        List<DataStatisticsVo> excelStatisticsDataList = dataStatisticsService.getMsgStatisticsDataList();
        return ResponseData.success(excelStatisticsDataList);
    }


    @GetResource(path = "/trigger",requiredLogin = false)
    @Operation(summary = "trigger statistics data ", description = "trigger statistics data")
    public ResponseData<Void> triggerStatisticsData() {
        dataStatisticsService.dailyStatistics();
        return ResponseData.success();
    }
}

