зФ® Node.js еОЯзФЯ fetch зФЯжИР Web жО•еП£зЪДеЕ®и¶ЖзЫЦиЗ™еК®еМЦжµЛиѓХиДЪжЬђпЉМ360 еЇ¶жЧ†ж≠їиІТгАВ

## еПВжХ∞

 вАФ жО•еП£жЦЗж°£иЈѓеЊДгАБController дї£з†БиЈѓеЊДгАБAPI еЙНзЉАгАБжИЦйЬАи¶БжµЛиѓХзЪДеКЯиГљжППињ∞

## йАВзФ®еЬЇжЩѓ

- еРОзЂѓжО•еП£еЉАеПСеЃМжИРеРОзЪДй™МжФґжµЛиѓХ
- жµЛиѓХзОѓеҐГйГ®зљ≤еРОзЪДеЖТзГЯжµЛиѓХ
- жО•еП£йЗНжЮДеРОзЪДеЫЮељТжµЛиѓХ
- жЦ∞еКЯиГљдЄКзЇњеЙНзЪДеЕ®йЗПжО•еП£й™МиѓБ

## жЙІи°Мж≠•й™§

### зђђдЄАж≠•пЉЪжФґйЫЖдњ°жБѓ

1. **иѓїжО•еП£жЦЗж°£**пЉИmd / swagger / дї£з†Бж≥®йЗКпЉЙпЉМжПРеПЦ**жЙАжЬЙ**жО•еП£иЈѓеЊДгАБжЦєж≥ХгАБеПВжХ∞гАБињФеЫЮеАЉ
   - зЙєеИЂж≥®жДПпЉЪеНХдЄ™/жЙєйЗПзЙИжЬђењЕй°їйГљеИЧеЗЇпЉИе¶В editRole / batchEditRoleгАБdeleteRole / batchDeleteRoleпЉЙ
2. **иѓї Controller дї£з†Б**пЉМз°ЃиЃ§пЉЪ
   - жЭГйЩРж≥®иІ£пЉИеУ™дЇЫжО•еП£йЬАи¶БзЩїељХгАБйЬАи¶БдїАдєИиІТиЙ≤пЉЙ
   - еПВжХ∞ж†°й™Мж≥®иІ£пЉИ@ValidгАБ@NotNullгАБ@NotEmptyгАБ@MinгАБ@MaxпЉЙвАФвАФ зЙєеИЂеЕ≥ж≥®**еИЧи°®еПВжХ∞жШѓеР¶ж†°й™МдЇЖз©ЇеИЧи°®**
   - ињФеЫЮеАЉз±їеЮЛеТМзїУжЮД
   - **жЭГйЩРж†°й™МеЉВеЄЄжШѓеР¶иҐЂзїЯдЄАеЉВеЄЄе§ДзРЖеЩ®ж≠£з°ЃжШ†е∞Д**пЉИжШѓињФеЫЮ 403 ињШжШѓ 500пЉЯпЉЙ
3. **иѓї Service/Manager еЃЮзО∞дї£з†Б**пЉМйЗНзВєеЕ≥ж≥®пЉЪ
   - еЖЩжУНдљЬзЪД upsert йАїиЊСжШѓеР¶зЬЯзЪДиГљ updateпЉИMyBatis-Plus `saveOrUpdateBatch` еЯЇдЇОдЄїйФЃпЉМдЄНеЯЇдЇОдЄЪеК°еФѓдЄАйФЃпЉЙ
   - еРМз±їжО•еП£зЪДйАїиЊСеѓєзІ∞жАІпЉИе¶В listA иАГиЩСзїІжЙњдљЖ listB дЄНиАГиЩСпЉЙ
   - еЖЕе≠ШеОїйЗНпЉИ`Collectors.toMap(..., (a,b)->a)`пЉЙжШѓеР¶жО©зЫЦдЇЖ DB е±ВйЗНе§НжХ∞жНЃ
4. **жЯ•жХ∞жНЃеЇУ**жЙЊжµЛиѓХжХ∞жНЃ + ж£АжЯ•жХ∞жНЃиі®йЗПпЉЪ
   - зЫЃж†ЗиµДжЇРзЪД IDпЉИз©ЇйЧі IDгАБиКВзВє IDгАБжЦЗж°£ ID з≠ЙпЉЙ
   - жЙАжЬЙзЫЄеЕ≥зФ®жИЈеПКеЕґиІТиЙ≤пЉИowner / admin / manager / editor / reader / е§ЦйГ® / з≥їзїЯпЉЙ
   - зФ® `SELECT` з°ЃиЃ§жХ∞жНЃе≠ШеЬ®пЉМдЄНи¶БеБЗиЃЊ
   - **жЯ•йЗНе§НжХ∞жНЃ**пЉЪ`SELECT count(*), col1, col2 FROM table GROUP BY col1, col2 HAVING count(*) > 1`
   - **жЯ•еФѓдЄАзіҐеЉХ**пЉЪ`SELECT INDEX_NAME, COLUMN_NAME, NON_UNIQUE FROM information_schema.STATISTICS WHERE TABLE_NAME = 'xxx'`
5. **з°ЃиЃ§иЃ§иѓБжЬЇеИґ**пЉЪ
   - жµЛиѓХзЩїељХеЕ•еП£пЉИtestLogin жО•еП£ / жµЛиѓХ token / OAuth mockпЉЙ
   - CSRF жЬЇеИґпЉИXSRF-TOKEN cookie йЬАеРМжЧґдљЬдЄЇ header еПСйАБпЉЙ
   - Session жЬЇеИґпЉИcookie еРНзІ∞гАБињЗжЬЯз≠ЦзХ•пЉЙ
6. **з°ЃиЃ§жµЛиѓХзОѓеҐГеЬ∞еЭА**еТМзЂѓеП£

### зђђдЇМж≠•пЉЪзФЯжИРжµЛиѓХиДЪжЬђ

зФЯжИР `test-api.js`пЉМжЦЗдїґзїУжЮДеЫЇеЃЪе¶ВдЄЛпЉЪ

```javascript
/**
 * [еКЯиГљеРНзІ∞] - жО•еП£жµЛиѓХиДЪжЬђ
 *
 * зФ®ж≥Х: node test-api.js
 * и¶Бж±В: Node.js 18+пЉИеОЯзФЯ fetchпЉЙ
 * иЗ™еК®зЩїељХжµЛиѓХзОѓеҐГпЉМжЧ†йЬАжЙЛеК®е°Ђ Cookie
 */

// ========== йЕНзљЃ ==========
const CONFIG = {
  host: 'http://xxx-test.example.com',
  loginEmail: 'test@example.com',
  // ... дЄЪеК°зЫЄеЕ≥зЪД ID
};

// ========== жµЛиѓХж°ЖжЮґ ==========
let passed = 0;
let failed = 0;
let cookie = '';
let xsrfToken = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  вЬЕ ${name}`);
    passed++;
  } else {
    console.log(`  вЭМ ${name}`);
    if (detail !== undefined)
      console.log(`     еЃЮйЩЕеАЉ:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 200) : detail);
    failed++;
  }
}

// ========== HTTP еЈ•еЕЈ ==========

/** дїО set-cookie е§ідЄ≠жПРеПЦ cookie еАЉ */
function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const [k, v] = kv.split('=');
    cookies[k.trim()] = v.trim();
  }
  return cookies;
}

async function rawFetch(method, url, body) {
  const headers = {
    'x-space-id': CONFIG.spaceId,      // жМЙй°єзЫЃеЃЮйЩЕ header и∞ГжХі
    'content-type': 'application/json',
  };
  if (cookie) headers['cookie'] = cookie;
  if (xsrfToken) headers['x-xsrf-token'] = xsrfToken;

  const opts = { method, headers, redirect: 'manual' };
  if (body) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
  return res.json();
}

async function POST(path, body) {
  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body);
  return res.json();
}

// ========== зЩїељХзЃ°зРЖ ==========

async function login() {
  console.log(`рЯФС зЩїељХ ${CONFIG.loginEmail} ...`);
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.loginEmail}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log('вЭМ зЩїељХе§±иі•');
    process.exit(1);
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  console.log(`   вЬЕ зЩїељХжИРеКЯ\n`);
}

let savedSessions = {};
function saveSession(name) {
  savedSessions[name] = { cookie, xsrfToken };
}
function restoreSession(name) {
  ({ cookie, xsrfToken } = savedSessions[name]);
}

async function loginAs(email) {
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${email}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log(`  вЪ†пЄП  зЩїељХ ${email} е§±иі•пЉМиЈ≥ињЗ`);
    return false;
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  return true;
}

// ========== жµЛиѓХзФ®дЊЛ ==========
// жѓПзїДдЄАдЄ™ async functionпЉМжМЙзїіеЇ¶зїДзїЗ

// ========== жЙІи°М ==========
async function main() {
  console.log('рЯЪА [еКЯиГљеРНзІ∞] - жО•еП£жµЛиѓХ');
  try {
    await login();
    // await testXxx(); ...
  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\nвЭМ жЧ†ж≥ХињЮжО•жµЛиѓХзОѓеҐГпЉМиѓЈж£АжЯ•зљСзїЬ');
    } else {
      console.log(`\nвЭМ еЉВеЄЄ: ${e.stack || e.message}`);
    }
    process.exit(1);
  }
  console.log(`\n=============================`);
  console.log(`вЬЕ йАЪињЗ: ${passed}  вЭМ е§±иі•: ${failed}  рЯУК жАїиЃ°: ${passed + failed}`);
  console.log(`=============================`);
  process.exit(failed > 0 ? 1 : 0);
}
main();
