// ========== жµЛиѓХж°ЖжЮґ ==========
let passed = 0;
let failed = 0;

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  вЬЕ ${name}`);
    passed++;
  } else {
    console.log(`  вЭМ ${name}`);
    if (detail !== undefined)
      console.log(`     еЃЮйЩЕеАЉ:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP еЈ•еЕЈ ==========
async function GET(path) {
  const res = await fetch(`${CONFIG.host}/api/v1${path}`, {
    method: 'GET',
    headers: { 'content-type': 'application/json' },
  });
  return res.json();
}

