// зїіеЇ¶ 1пЉЪж≠£еЄЄжµБз®Л
async function testBasicCall() {
  console.log('рЯУЛ 1. еЯЇжЬђи∞ГзФ®');

  const res = await GET('/node/statistics/view/count');
  assert('жО•еП£ињФеЫЮ success', res.success === true, res);
  assert('code дЄЇ 200', res.code === 200, res.code);
  assert('data дЄНдЄЇ null', res.data != null, res.data);

  if (res.data) {
    const d = res.data;
    // 7 дЄ™иІЖеЫЊз±їеЮЛе≠ЧжЃµ
    assert('gridViewNum дЄЇжХ∞е≠Ч', typeof d.gridViewNum === 'number', d.gridViewNum);
    assert('kanbanViewNum дЄЇжХ∞е≠Ч', typeof d.kanbanViewNum === 'number', d.kanbanViewNum);
    assert('galleryViewNum дЄЇжХ∞е≠Ч', typeof d.galleryViewNum === 'number', d.galleryViewNum);
    assert('calendarViewNum дЄЇжХ∞е≠Ч', typeof d.calendarViewNum === 'number', d.calendarViewNum);
    assert('ganttViewNum дЄЇжХ∞е≠Ч', typeof d.ganttViewNum === 'number', d.ganttViewNum);
    assert('architectureViewNum дЄЇжХ∞е≠Ч', typeof d.architectureViewNum === 'number', d.architectureViewNum);
    assert('hierarchyViewNum дЄЇжХ∞е≠Ч', typeof d.hierarchyViewNum === 'number', d.hierarchyViewNum);

    // зїЯиЃ°жЧ•жЬЯ
    assert('statisticsDay дЄНдЄЇз©Ї', d.statisticsDay != null && d.statisticsDay !== '', d.statisticsDay);
    assert('statisticsDay ж†ЉеЉПдЄЇжЧ•жЬЯ', /^\d{4}-\d{2}-\d{2}/.test(d.statisticsDay), d.statisticsDay);

    // жХ∞еАЉеРИзРЖжАІ
    assert('gridViewNum >= 0', d.gridViewNum >= 0, d.gridViewNum);
    assert('kanbanViewNum >= 0', d.kanbanViewNum >= 0, d.kanbanViewNum);
    assert('galleryViewNum >= 0', d.galleryViewNum >= 0, d.galleryViewNum);
    assert('calendarViewNum >= 0', d.calendarViewNum >= 0, d.calendarViewNum);
    assert('ganttViewNum >= 0', d.ganttViewNum >= 0, d.ganttViewNum);
    assert('architectureViewNum >= 0', d.architectureViewNum >= 0, d.architectureViewNum);
    assert('hierarchyViewNum >= 0', d.hierarchyViewNum >= 0, d.hierarchyViewNum);

    // gridViewNum еЇФиѓ•жШѓжЬАе§ЪзЪДпЉИи°®ж†ЉиІЖеЫЊжШѓйїШиЃ§иІЖеЫЊпЉЙ
    assert('gridViewNum дЄЇжЬАе§ІеАЉпЉИйїШиЃ§иІЖеЫЊпЉЙ',
      d.gridViewNum >= d.kanbanViewNum &&
      d.gridViewNum >= d.galleryViewNum &&
      d.gridViewNum >= d.calendarViewNum &&
      d.gridViewNum >= d.ganttViewNum &&
      d.gridViewNum >= d.architectureViewNum &&
      d.gridViewNum >= d.hierarchyViewNum,
      d);

    // ж≤°жЬЙе§ЪдљЩе≠ЧжЃµ
    const expectedKeys = ['gridViewNum', 'kanbanViewNum', 'galleryViewNum',
      'calendarViewNum', 'ganttViewNum', 'architectureViewNum', 'hierarchyViewNum',
      'statisticsDay'];
    const actualKeys = Object.keys(d);
    const extraKeys = actualKeys.filter(k => !expectedKeys.includes(k));
    assert('жЧ†е§ЪдљЩе≠ЧжЃµ', extraKeys.length === 0, extraKeys);
  }
}

// зїіеЇ¶ 2пЉЪдЄ§жђ°и∞ГзФ®дЄАиЗіжАІпЉИжХ∞жНЃз®≥еЃЪжАІпЉЙ
async function testConsistency() {
  console.log('\nрЯФД 2. жХ∞жНЃдЄАиЗіжАІ');

  const res1 = await GET('/node/statistics/view/count');
  const res2 = await GET('/node/statistics/view/count');

  assert('дЄ§жђ°и∞ГзФ® gridViewNum дЄАиЗі',
    res1.data?.gridViewNum === res2.data?.gridViewNum);
  assert('дЄ§жђ°и∞ГзФ® statisticsDay дЄАиЗі',
    res1.data?.statisticsDay === res2.data?.statisticsDay);
  assert('дЄ§жђ°и∞ГзФ®жЙАжЬЙе≠ЧжЃµдЄАиЗі',
    JSON.stringify(res1.data) === JSON.stringify(res2.data));
}

// зїіеЇ¶ 9пЉЪеєґеПСиѓЈж±В
async function testConcurrency() {
  console.log('\nрЯФА 3. еєґеПСиѓЈж±В');

  const promises = Array.from({ length: 10 }, () =>
    GET('/node/statistics/view/count')
  );
  const results = await Promise.all(promises);

  const allSuccess = results.every(r => r.success === true);
  assert('10 дЄ™еєґеПСиѓЈж±ВйГљжИРеКЯ', allSuccess);

  // еєґеПСзїУжЮЬдЄАиЗі
  const firstData = JSON.stringify(results[0].data);
  const allConsistent = results.every(r => JSON.stringify(r.data) === firstData);
  assert('еєґеПСзїУжЮЬжХ∞жНЃдЄАиЗі', allConsistent);
}

// зїіеЇ¶ 10пЉЪеУНеЇФзїУжЮДдЄАиЗіжАІпЉИдЄО success=false еЬЇжЩѓеѓєжѓФпЉЙ
async function testResponseStructure() {
  console.log('\nрЯУ¶ 4. еУНеЇФзїУжЮД');

  const res = await GET('/node/statistics/view/count');
  assert('й°ґе±ВеРЂ success', 'success' in res, Object.keys(res));
  assert('й°ґе±ВеРЂ code', 'code' in res, Object.keys(res));
  assert('й°ґе±ВеРЂ data', 'data' in res, Object.keys(res));
  assert('й°ґе±ВеРЂ message', 'message' in res, Object.keys(res));
}

// йҐЭе§ЦпЉЪдЄНе≠ШеЬ®зЪДиЈѓеЊДдЄНељ±еУН
async function testWrongPath() {
  console.log('\nрЯЪЂ 5. йФЩиѓѓиЈѓеЊД');

  const res = await fetch(`${CONFIG.host}/api/v1/node/statistics/view/count/nonexist`, {
    method: 'GET',
    headers: { 'content-type': 'application/json' },
  });
  assert('дЄНе≠ШеЬ®иЈѓеЊДињФеЫЮйЭЮ 200', res.status !== 200, res.status);
}

// ========== жЙІи°М ==========
async function main() {
  console.log('рЯЪА жЩЇиГљи°®ж†ЉиІЖеЫЊз±їеЮЛзїЯиЃ° - жО•еП£жµЛиѓХ\n');
  console.log(`   зОѓеҐГ: ${CONFIG.host}`);
  console.log(`   жО•еП£: GET /api/v1/node/statistics/view/count\n`);

  try {
    await testBasicCall();
    await testConsistency();
    await testConcurrency();
    await testResponseStructure();
    await testWrongPath();
  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\nвЭМ жЧ†ж≥ХињЮжО•жµЛиѓХзОѓеҐГпЉМиѓЈж£АжЯ•зљСзїЬ');
    } else {
      console.log(`\nвЭМ еЉВеЄЄ: ${e.stack || e.message}`);
    }
    process.exit(1);
  }

  console.log(`\n=============================`);
  console.log(`вЬЕ йАЪињЗ: ${passed}  вЭМ е§±иі•: ${failed}  рЯУК жАїиЃ°: ${passed + failed}`);
  console.log(`=============================`);
  process.exit(failed > 0 ? 1 : 0);
}

main();

